import{_ as e,o as i,c as t,ak as s,al as r,am as n,an as o}from"./chunks/framework.Bi-31Ycc.js";const f=JSON.parse('{"title":"Android App","description":"Punjab Educare on Android (student learning, teacher tools, and internal administration).","frontmatter":{"title":"Android App","description":"Punjab Educare on Android (student learning, teacher tools, and internal administration)."},"headers":[],"relativePath":"punjab-educare/android.md","filePath":"punjab-educare/android.md","lastUpdated":1772239018000}'),l={name:"punjab-educare/android.md"};function d(c,a,p,u,h,m){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="android-app" tabindex="-1">Android App <a class="header-anchor" href="#android-app" aria-label="Permalink to “Android App”">​</a></h1><p>Punjab Educare’s Android app is the primary client for the platform, providing a role-aware experience for students and teachers, with internal administration capabilities used by the trusted admin team.</p><div class="info custom-block"><p class="custom-block-title">Scope</p><p>This page describes user-facing capabilities and the mobile tech stack at a high level. It intentionally avoids technical details that could enable external use of the internal backend.</p></div><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to “Download”">​</a></h2><div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap;"><a href="https://play.google.com/store/apps/details?id=com.deepakkumar.PunjabEducare" target="_blank"><img src="'+r+'" alt="" width="150"></a><a href="https://www.indusappstore.com/apps/education/punjab-educare/com.deepakkumar.PunjabEducare" target="_blank"><img class="light-only" src="'+n+'" alt="Download on Indus Appstore" width="150"><img class="dark-only" src="'+o+'" alt="Download on Indus Appstore" width="150"></a></div><h2 id="what-users-can-do" tabindex="-1">What users can do <a class="header-anchor" href="#what-users-can-do" aria-label="Permalink to “What users can do”">​</a></h2><h3 id="students" tabindex="-1">Students <a class="header-anchor" href="#students" aria-label="Permalink to “Students”">​</a></h3><ul><li>Attempt practice quizzes and view participation-related counters.</li><li>Log in multiple students on the same device (useful for shared devices).</li><li>Start available quizzes and complete attempts with localized subject/topic display.</li></ul><h3 id="teachers" tabindex="-1">Teachers <a class="header-anchor" href="#teachers" aria-label="Permalink to “Teachers”">​</a></h3><ul><li>Complete teacher onboarding and verification before accessing teacher tools.<br><a href="/products/punjab-educare/teacher-registration">Teacher Registration</a></li><li>Submit questions through a guided workflow designed for quality and consistency.<br><a href="/products/punjab-educare/question-submissions">Question Submissions</a></li><li>Use classroom assessment tools such as quiz setup and results viewing (availability may vary by release stage).</li></ul><h3 id="admins" tabindex="-1">Admins <a class="header-anchor" href="#admins" aria-label="Permalink to “Admins”">​</a></h3><p>The platform includes internal administration capabilities used by a trusted team of carefully selected teachers to maintain quality across classes and subjects.</p><ul><li>Review and approve teacher-submitted questions before they are published to the main question bank.</li><li>Manage question bank quality through auditing and editorial workflows.</li><li>Manage platform communication surfaces (e.g., notifications, greetings) and review user feedback.</li><li>Maintain academic structure data (schools, classes, subjects/topics) and monitor platform status.</li></ul><div class="warning custom-block"><p class="custom-block-title">Access</p><p>Administration features are not publicly accessible and are intended only for the trusted internal admin team.</p></div><h2 id="system-notifications" tabindex="-1">System notifications <a class="header-anchor" href="#system-notifications" aria-label="Permalink to “System notifications”">​</a></h2><p>Punjab Educare supports device-level notifications for important updates.</p><ul><li>Broadcast notifications: platform-wide announcements can be sent to all users.</li><li>Teacher-targeted notifications: individual teachers can receive status updates such as account approval or account rejection.</li></ul><h2 id="key-platform-behavior" tabindex="-1">Key platform behavior <a class="header-anchor" href="#key-platform-behavior" aria-label="Permalink to “Key platform behavior”">​</a></h2><ul><li>Teacher-submitted questions are reviewed by the trusted internal admin team before entering the main question bank.</li><li>The app supports multilingual presentation: English, Punjabi, and Hindi.</li></ul><h2 id="tech-stack" tabindex="-1">Tech stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to “Tech stack”">​</a></h2><p><strong>Mobile App</strong> — Flutter &amp; Dart with Material Design.<br><code>Flutter</code> <code>Dart</code> <code>Material Design</code></p><h2 id="privacy-policy" tabindex="-1">Privacy policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to “Privacy policy”">​</a></h2><p>The Android Privacy Policy page exists to satisfy Play Store requirements and explain how the Android app handles user data.<br><a href="/products/punjab-educare/privacy-policy">Privacy Policy</a></p>',23)])])}const y=e(l,[["render",d]]);export{f as __pageData,y as default};
